onClick:
{{
appsmith.store.modoSA === "MODIFICAR"

? qrySAModificar.run(

() => {

    storeValue("ultimaSATrabajada", qrySAModificar.data[0].numero_solicitud_avance);

    storeValue("idUltimaSATrabajada", qrySAModificar.data[0].id_solicitud_avance);

    storeValue("idSAActual", null);

    storeValue("modoSA", "CREACION");

    storeValue("ocSAActual", null);

    storeValue("saActual", null);

    resetWidget("inpIdOCllamar");

    resetWidget("inpObservacionSA");

    resetWidget("inpMontoSolicitadoSA");

    resetWidget("selOtraMonedaSA");
    resetWidget("inpTasaOtraMonedaSA");
    resetWidget("selOtraMonedaCodigoSA");

    resetWidget("inpRetIbisSA");
    resetWidget("inpRetDGIISA");
    resetWidget("inpRetGarantiaSA");
    resetWidget("inpRetTSSSA");

    showAlert(
        "Solicitud de Avance modificada correctamente.",
        "success"
    );

},

(error) => {

    showAlert(error.message, "error");

}

)

: qrySACrear.run(

() => {

    storeValue("ultimaSATrabajada", qrySACrear.data[0].numero_solicitud_avance);

    storeValue("idUltimaSATrabajada", qrySACrear.data[0].id_solicitud_avance);

    storeValue("idSAActual", null);

    storeValue("modoSA", "CREACION");

    storeValue("ocSAActual", null);

    storeValue("saActual", null);

    resetWidget("inpIdOCllamar");

    resetWidget("inpObservacionSA");

    resetWidget("inpMontoSolicitadoSA");

    resetWidget("selOtraMonedaSA");
    resetWidget("inpTasaOtraMonedaSA");
    resetWidget("selOtraMonedaCodigoSA");

    resetWidget("inpRetIbisSA");
    resetWidget("inpRetDGIISA");
    resetWidget("inpRetGarantiaSA");
    resetWidget("inpRetTSSSA");

    showAlert(
        "Solicitud de Avance creada correctamente.",
        "success"
    );

},

(error) => {

    showAlert(error.message, "error");

}

)

}}
